import{_ as a,o,c,a3 as t}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Module extract:compiler","description":"extract:compiler 模块负责加载、解析和归一化编译数据库（如 compile_commands.json），并提供对单个编译条目进行标准化处理的核心流程。它公开定义了 CompileEntry、CompilationDatabase 和 CompDbError 等数据结构，用于表示编译命令、数据库及错误信息。模块的公开函数涵盖从文件路径加载数据库（load_compdb）、在数据库中按源文件查找条目（lookup）、标准化条目中的文件路径与参数（normalize_entry_file、normalize_argument_path、sanitize_driver_arguments、sanitize_tool_arguments）、生成唯一编译签名与缓存键（build_compile_signature、ensure_cache_key）、缓存工具链查询结果（query_toolchain_cached）以及最终基于归一化后的条目创建编译器实例（create_compiler_instance）等关键操作，为后续代码提取与分析提供稳定可重复的编译上下文。","frontmatter":{"title":"Module extract:compiler","description":"extract:compiler 模块负责加载、解析和归一化编译数据库（如 compile_commands.json），并提供对单个编译条目进行标准化处理的核心流程。它公开定义了 CompileEntry、CompilationDatabase 和 CompDbError 等数据结构，用于表示编译命令、数据库及错误信息。模块的公开函数涵盖从文件路径加载数据库（load_compdb）、在数据库中按源文件查找条目（lookup）、标准化条目中的文件路径与参数（normalize_entry_file、normalize_argument_path、sanitize_driver_arguments、sanitize_tool_arguments）、生成唯一编译签名与缓存键（build_compile_signature、ensure_cache_key）、缓存工具链查询结果（query_toolchain_cached）以及最终基于归一化后的条目创建编译器实例（create_compiler_instance）等关键操作，为后续代码提取与分析提供稳定可重复的编译上下文。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/compiler.md","filePath":"zh/clore/modules/extract/compiler.md"}'),r={name:"zh/clore/modules/extract/compiler.md"};function i(d,e,l,s,n,p){return o(),c("div",null,[...e[0]||(e[0]=[t("",198)])])}const u=a(r,[["render",i]]);export{m as __pageData,u as default};
